$ry(".submit").click(e=>{e.preventDefault();const nickName=$ry(".nickName").val();nickName?axios({method:"post",url:"/api/user/resister",data:$ryTools.stringify({nickName:nickName})}).then(({data:res})=>{0===res.code?($ryTools.notify({description:"登录成功，跳转中···"}),setTimeout(()=>{window.location.reload()},1e3)):$ryTools.notify({description:res.msg,type:"error"})}):$ryTools.notify({description:"不可为空",type:"error"})});